<?php
/**
 * Makes JetEngine compatible with WP-Parsidate plugin
 *
 * @package                 WP-Parsidate
 * @subpackage              Plugins/JetEngine
 */

namespace WPParsidate\App\Integration;

defined( 'ABSPATH' ) || exit;

use Jet_Engine_Render_Dynamic_Field;
use WPParsidate\Addons\Addon;
use WPParsidate\Helper\Date;

class JetEngine extends Addon {
  public string $addonID = 'jet_engine';
  public string $currentTab = 'integration';

  public function initAction(): void {
//    add_filter( 'cx_term_meta/date', [ $this, 'metaToDate' ], 10, 3 );
//    add_filter( 'jet-engine/custom-content-types/date', [ $this, 'metaToDate' ], 10, 3 );
    add_filter( 'jet-engine/listings/dynamic-field/custom-value', [ $this, 'convertDateMeta' ], 10, 3 );
  }

  /**
   * Convert date/datetime meta value to Shamsi date
   *
   * @param string|null $value Value
   * @param array $settings Settings
   * @param Jet_Engine_Render_Dynamic_Field $dynamicField Field
   *
   * @return null|string
   */
  public function convertDateMeta( ?string $value, $settings, $dynamicField ): ?string {
    $source = $dynamicField->get( 'dynamic_field_source' );
    if ( $source !== 'meta' || is_admin() || wp_doing_ajax() || ( $this->getSetting( 'date_to_shamsi', false ) === false && $this->getSetting( 'datetime_to_shamsi', false ) === false ) ) {
      return $value;
    }

    $objectContext = $dynamicField->get( 'object_context' );
    $field         = ! empty( $settings['dynamic_field_post_meta_custom'] ) ? $settings['dynamic_field_post_meta_custom'] : false;

    if ( ! $field && isset( $settings['dynamic_field_post_meta'] ) ) {
      $field = ! empty( $settings['dynamic_field_post_meta'] ) ? $settings['dynamic_field_post_meta'] : false;
    }

    if ( $field ) {
      $result = jet_engine()->listings->data->get_meta_by_context( $field, $objectContext );
      if ( ! $result ) {
        return $value;
      }

      $isDate     = Date::isDateString( $result, 'Y-m-d' );
      $isDateTime = Date::isDateString( $result, 'Y-m-d\TH:i' );

      if ( $isDate['type'] === 'gregorian' && $this->getSetting( 'date_to_shamsi', false ) ) {
        $value = parsidate( $this->getSetting( 'date_format', 'j F Y' ), $result, true );

      } else if ( $isDateTime['type'] === 'gregorian' && $this->getSetting( 'datetime_to_shamsi', false ) ) {
        $value = parsidate( $this->getSetting( 'datetime_format', 'j F Y, g:i a' ), $result, true );
      }
    }

    //$value = parsidate();

    return $value;
  }

  /**
   * Convert meta value date to formatted date according timezone settings
   *
   * @param string $timestamp [description]
   * @param string $raw_time [description]
   *
   * @return string            [description]
   */
  public function metaToDate( $formatted_date, $timestamp, $format ) {
    return $formatted_date;
  }

  public function addSectionSettings( $sections ) {
    $sections[ $this->addonID ] = array(
      'title'        => esc_html__( 'Jet Engine', 'wp-parsidate' ),
      'desc'         => esc_html__( 'ParsiDate integration for Jet Engine', 'wp-parsidate' ),
      'settings_key' => $this->addonID,
      'settings'     => [
        'jetengine_start_grid' => array(
          'id'    => 'edd_start_grid',
          'title' => esc_html__( 'Meta date field conversion', 'wp-parsidate' ),
          'type'  => 'startGrid',
        ),
        'convert_notice'       => array(
          'id'      => 'convert_notice',
          'notices' => array(
            array(
              'message' => esc_html__( 'Currently only "Dynamic Field" is supported.', 'wp-parsidate' ),
              'type'    => 'warning'
            )
          ),
          'type'    => 'notice',
        ),
        'date_to_shamsi'       => array(
          'id'       => 'date_to_shamsi',
          'title'    => esc_html__( 'Date field to Shamsi', 'wp-parsidate' ),
          'type'     => 'toggle',
          'default'  => false,
          'sanitize' => 'bool'
        ),
        'date_format'          => array(
          'id'      => 'date_format',
          'title'   => esc_html__( 'Date format', 'wp-parsidate' ),
          'type'    => 'text',
          'default' => 'j F Y',
          'class'   => 'ltr-field',
        ),
        'datetime_to_shamsi'   => array(
          'id'       => 'datetime_to_shamsi',
          'title'    => esc_html__( 'Datetime field to Shamsi', 'wp-parsidate' ),
          'type'     => 'toggle',
          'default'  => false,
          'sanitize' => 'bool'
        ),
        'datetime_format'      => array(
          'id'      => 'datetime_format',
          'title'   => esc_html__( 'Datetime format', 'wp-parsidate' ),
          'type'    => 'text',
          'default' => 'j F Y, g:i a',
          'class'   => 'ltr-field',
        ),
        'jetengine_end_grid'   => array(
          'type' => 'endGrid',
        )
      ]
    );

    return $sections;
  }

